import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const AdminScreen = () => {
  const [users, setUsers] = useState([]);
  const [products, setProducts] = useState([]);
  const [orders, setOrders] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    const userInfo = JSON.parse(localStorage.getItem("userInfo"));
    if (!userInfo) {
      navigate("/");
      return;
    }

    fetchAll();
  }, [navigate]);

  const fetchAll = async () => {
    try {
      const usersData = await axios.get("http://localhost:5000/api/users");
      const productsData = await axios.get("http://localhost:5000/api/products");
      const ordersData = await axios.get("http://localhost:5000/api/orders");

      setUsers(usersData.data);
      setProducts(productsData.data);
      setOrders(ordersData.data);
    } catch (error) {
      console.log(error);
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h1>Admin Panel</h1>

      <h2>Users</h2>
      {users.map((u) => (
        <p key={u._id}>{u.name} - {u.email}</p>
      ))}

      <h2>Products</h2>
      {products.map((p) => (
        <p key={p._id}>{p.name} - ₹{p.price}</p>
      ))}

      <h2>Orders</h2>
      {orders.map((o) => (
        <p key={o._id}>{o._id} - ₹{o.totalAmount}</p>
      ))}
    </div>
  );
};

export default AdminScreen;
